import java.io.*;
import javax.servlet.*;
import javax.servlet.http.*;

public class SecureServlet extends HttpServlet {
    protected void doPost(HttpServletRequest request, HttpServletResponse response)
            throws ServletException, IOException {
        response.setContentType("text/html");
        PrintWriter out = response.getWriter();

        String userInput = request.getParameter("input");

        out.println("<html>");
        out.println("<head><title>Output</title></head>");
        out.println("<body>");
        out.println("<h1>User Input:</h1>");

        // Properly encode user input to prevent XSS attacks
        String encodedUserInput = encodeForHtml(userInput);
        out.println(encodedUserInput);

        out.println("</body>");
        out.println("</html>");
    }

    private String encodeForHtml(String input) {
        return input
                .replace("&", "&amp;")
                .replace("<", "&lt;")
                .replace(">", "&gt;")
                .replace("\"", "&quot;")
                .replace("'", "&#39;");
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
